def perceive(data):
    out = {}
    if isinstance(data, dict):
        price = data.get("price")
        who = data.get("from") or data.get("agent") or data.get("by")
        if price is not None:
            out["current_offer"] = float(price)
        if who in ("buyer", "seller"):
            out["offer_by"] = who
        return out
    text = str(data).lower()
    if "buyer" in text:
        out["offer_by"] = "buyer"
    elif "seller" in text:
        out["offer_by"] = "seller"
    num = ""
    for ch in text:
        if ch.isdigit() or ch == ".":
            num += ch
        elif num:
            break
    if num:
        out["current_offer"] = float(num)
    return out
